from pathlib import Path

_NOTES_DIR = Path(__file__).resolve().parent.parent / "notes"


def _resolve_note_path(note_id: str) -> Path:
    if not note_id or note_id.strip() != note_id:
        raise ValueError("invalid note id")
    if "/" in note_id or "\\" in note_id or ".." in note_id:
        raise ValueError("invalid note id")
    if len(note_id) > 64:
        raise ValueError("invalid note id")
    notes_root = _NOTES_DIR.resolve()
    path = (notes_root / note_id).resolve()
    if not path.is_relative_to(notes_root):
        raise ValueError("invalid note id")
    return path


def read_note(note_id: str) -> str:
    return _resolve_note_path(note_id).read_text(encoding="utf-8")
